/**
 * @summary List decision ledger entries for a project
 */
export const getListEntriesUrl = (
  projectId: number,
  params?: ListEntriesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/projects/${projectId}/entries?${stringifiedParams}`
    : `/api/projects/${projectId}/entries`;
};

export const listEntries = async (
  projectId: number,
  params?: ListEntriesParams,
  options?: RequestInit,
): Promise<Entry[]> => {
  return customFetch<Entry[]>(getListEntriesUrl(projectId, params), {
    ...options,
    method: "GET",
  });
};

