export type ReopenEntryMutationResult = NonNullable<
  Awaited<ReturnType<typeof reopenEntry>>
>;

export type ReopenEntryMutationError = ErrorType<void>;

/**
 * @summary Reopen a committed entry as a new draft
 */
export const useReopenEntry = <
  TError = ErrorType<void>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof reopenEntry>>,
    TError,
    { id: number },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof reopenEntry>>,
  TError,
  { id: number },
  TContext
> => {
  return useMutation(getReopenEntryMutationOptions(options));
};

/**
 * @summary Send a message and get an AI response
 */
export const getSendMessageUrl = () => {
  return `/api/chat`;
};

export const sendMessage = async (
  chatRequest: ChatRequest,
  options?: RequestInit,
): Promise<ChatResponse> => {
  return customFetch<ChatResponse>(getSendMessageUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(chatRequest),
  });
};

export const getSendMessageMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof sendMessage>>,
    TError,
    { data: BodyType<ChatRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof sendMessage>>,
  TError,
  { data: BodyType<ChatRequest> },
  TContext
> => {
  const mutationKey = ["sendMessage"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof sendMessage>>,
    { data: BodyType<ChatRequest> }
  > = (props) => {
    const { data } = props ?? {};

    return sendMessage(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SendMessageMutationResult = NonNullable<
  Awaited<ReturnType<typeof sendMessage>>
>;
export type SendMessageMutationBody = BodyType<ChatRequest>;
export type SendMessageMutationError = ErrorType<unknown>;

/**
 * @summary Send a message and get an AI response
 */
export const useSendMessage = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof sendMessage>>,
    TError,
    { data: BodyType<ChatRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof sendMessage>>,
  TError,
  { data: BodyType<ChatRequest> },
  TContext
> => {
  return useMutation(getSendMessageMutationOptions(options));
};
